SELECT invoice_no
FROM invoices
ORDER BY invoice_no ASC;

SELECT SUM(amount) AS total_pending_amount
FROM invoices
WHERE invoice_id NOT IN (SELECT invoice_id FROM payments);

SELECT SUM(amount) AS total_due
FROM invoices
WHERE invoice_id NOT IN (SELECT invoice_id FROM invoice_status WHERE status = 'Paid');

SELECT invoice_no, amount
FROM invoices
WHERE invoice_id NOT IN (
  SELECT invoice_id
  FROM payments
);
